        "entities.TaxInvoiceStateEX": {
            "type": "object",
            "properties": {
                "barobillState": {
                    "description": "BarobillState represents the Barobill state\n1000: Temporary storage (임시저장)\n2010: Pre-issue approval pending (발급예정 승인대기)\n2011: Pre-issue approval completed (발급예정 승인완료)\n2020: Reverse-issue request pending (역발행요청 발급대기)\n3011: Pre-issue completed (발급예정 발급완료)\n3021: Reverse-issue request completed (역발행요청 발급완료)\n3014: Issue completed (발급완료)\n4012: Pre-issue rejected (발급예정 거부)\n4022: Reverse-issue request rejected (역발행요청 거부)\n5013: Pre-issue cancelled by supplier before approval (발급예정 승인 전 공급자에 의한 취소)\n5023: Reverse-issue request cancelled before approval (역발행요청 승인 전 공급받는자에 의한 취소)",
                    "type": "integer"
                },
                "invoiceKey": {
                    "description": "InvoiceKey is the invoice key from Barobill",
                    "type": "string"
                },
                "isConfirmed": {
                    "description": "IsConfirmed indicates whether the recipient confirmed the invoice\n0: Not confirmed (미확인)\n1: Confirmed (확인)",
                    "type": "integer"
                },
                "isOpened": {
                    "description": "IsOpened indicates whether the recipient opened the email\n0: Not opened (미개봉)\n1: Opened (개봉)",
                    "type": "integer"
                },
                "issueDT": {
                    "description": "IssueDT is the issue date and time (발급일시)\nFormat: YYYYMMDDHHMMSS",
                    "type": "string"
                },
                "mgtKey": {
                    "description": "MgtKey is the management key (관리번호)",
                    "type": "string"
                },
                "ntsResultDT": {
                    "description": "NTSResultDT is the National Tax Service transmission result received date and time (국세청 전송결과 수신일시)\nFormat: YYYYMMDDHHMMSS",
                    "type": "string"
                },
                "ntsSendDT": {
                    "description": "NTSSendDT is the National Tax Service transmission date and time (국세청 전송일시)\nFormat: YYYYMMDDHHMMSS",
                    "type": "string"
                },
                "ntsSendKey": {
                    "description": "NTSSendKey is the National Tax Service approval number (국세청 승인번호)",
                    "type": "string"
                },
                "ntsSendResult": {
                    "description": "NTSSendResult is the National Tax Service transmission result code (국세청 전송결과)",
                    "type": "string"
                },
                "ntsSendState": {
                    "description": "NTSSendState represents the National Tax Service transmission state\n1: Before transmission (전송전)\n2: Waiting for transmission (전송대기)\n3: Transmitting (전송중)\n4: Transmission completed (전송완료)\n5: Transmission failed (전송실패)",
                    "type": "integer"
                },
                "preIssueDT": {
                    "description": "PreIssueDT is the pre-issue date and time (발급예정일시)\nFormat: YYYYMMDDHHMMSS",
                    "type": "string"
                },
                "registDT": {
                    "description": "RegistDT is the registration date and time (등록일시)\nFormat: YYYYMMDDHHMMSS",
